import React from 'react';

function Skills({ data }) {
  if (!data) return null;

  const skillIcons = {
    'Problem Solving': '🧩',
    'Frontend': '🎨',
    'Backend': '⚙️',
    'UI/UX Design': '✏️',
    'Multi-tasking': '⚡'
  };

  return (
    <section id="skills" className="py-12 md:py-16 bg-gray-50">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Skills</h2>
          <div className="space-y-3">
            {data.map((skill, index) => (
              <div key={index} className="flex items-center justify-between p-4 rounded-lg border border-gray-200 hover:bg-gray-50 transition">
                <div className="flex items-center gap-3">
                  <span className="text-2xl">{skillIcons[skill.category] || '⭐'}</span>
                  <span className="font-semibold text-gray-800">{skill.category}</span>
                </div>
                <span className="text-sm font-semibold text-blue-600 bg-blue-50 px-3 py-1 rounded-full">
                  {skill.level}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Skills;
